[RequireComponent(typeof(Rigidbody))]
public class PlayerMovement : MonoBehaviour
{
    [SerializeField] float moveSpeed = 8f;
    [SerializeField] float jumpForce = 8f;

    private Rigidbody rb;
    private Vector3 moveDir;
    private bool isGrounded = false;

    private void Update()
    {
        float h = Input.GetAxisRaw("Horizontal");
        float v = Input.GetAxisRaw("Vertical");

        Vector3 camF = Vector3.Scale(
            Camera.main.transform.forward, 
            new Vector3(1, 0, 1)).normalized;
        Vector3 camR = Camera.main.transform.right;

        moveDir = (camF * v + camR * h).normalized;

        if (Input.GetKeyDown(KeyCode.Space) && isGrounded)
            jumpRequested = true;
    }

    private void FixedUpdate()
    {
        Vector3 force = moveDir * moveSpeed;
        rb.AddForce(isGrounded ? force : force * 0.5f, 
                    ForceMode.Force);

        if (jumpRequested)
        {
            rb.AddForce(Vector3.up * jumpForce, 
                       ForceMode.Impulse);
            isGrounded = false;
            jumpRequested = false;
        }
    }
}

// 베지어 곡선 기반 플레이어 이동
private IEnumerator MoveAlongCurve(Rigidbody playerRb)
{
    Vector3 startPos = playerRb.position;
    Vector3 controlPos = pointTransform.position;
    Vector3 endPos = palletTownTransform.position;

    float elapsed = 0f;

    while (elapsed < throwDuration)
    {
        float t = elapsed / throwDuration;

        // 2차 베지어 곡선 공식
        Vector3 bezierPos = 
            Mathf.Pow(1 - t, 2) * startPos +
            2 * (1 - t) * t * controlPos +
            Mathf.Pow(t, 2) * endPos;

        playerRb.MovePosition(bezierPos);
        elapsed += Time.fixedDeltaTime;
        yield return new WaitForFixedUpdate();
    }

    playerRb.MovePosition(endPos);
}

[System.Serializable]
public struct ReplayFrame
{
    public Vector3 playerPosition;
    public Quaternion playerRotation;
    public Vector3 cameraPosition;
    public Quaternion cameraRotation;
}

public class ReplayRecorder : MonoBehaviour
{
    public float duration = 1f;
    public float interval = 0.02f;

    private Queue<ReplayFrame> frameQueue 
        = new Queue<ReplayFrame>();

    void FixedUpdate()
    {
        timer += Time.fixedDeltaTime;
        if (timer >= interval)
        {
            timer = 0f;
            frameQueue.Enqueue(new ReplayFrame
            {
                playerPosition = Player.position,
                playerRotation = Player.rotation,
                cameraPosition = Camera.position,
                cameraRotation = Camera.rotation
            });

            // 오래된 프레임 자동 삭제
            while (frameQueue.Count > duration / interval)
                frameQueue.Dequeue();
        }
    }
}

public class ReplayPlayer : MonoBehaviour
{
    [SerializeField] private Volume deathVolume;
    [SerializeField] private float grayEffectDuration = 1f;
    private CinemachineBrain brain;

    public void PlayReplay(System.Action onComplete)
    {
        StartCoroutine(ActivateGrayEffect());
        StartCoroutine(ReplayCoroutine(onComplete));
    }

    private IEnumerator ReplayCoroutine(Action onComplete)
    {
        Time.timeScale = replayTime; // 0.5배속
        brain.enabled = false;

        var frames = recorder.FrameQueue.ToArray();
        foreach (var frame in frames)
        {
            Player.position = frame.playerPosition;
            Camera.position = frame.cameraPosition;
            yield return new WaitForSeconds(
                Time.fixedDeltaTime);
        }

        brain.enabled = true;
        onComplete?.Invoke();
    }
}

public class SoundManager : MonoBehaviour
{
    private static SoundManager instance;
    public static SoundManager Instance { get {...} }

    private Dictionary<string, AudioClip> audioClipsDic 
        = new Dictionary<string, AudioClip>();

    private void Awake()
    {
        if (Instance != this) {
            Destroy(gameObject);
            return;
        }
        DontDestroyOnLoad(gameObject);

        foreach (AudioClip clip in sfxAudioClips)
            audioClipsDic[clip.name] = clip;

        SceneManager.sceneLoaded += OnSceneLoaded;
    }

    public void PlaySFXSound(string name)
    {
        if (!audioClipsDic.ContainsKey(name)) return;

        GameObject sfxObj = new GameObject($"SFX_{name}");
        AudioSource source = sfxObj.AddComponent<AudioSource>();
        source.clip = audioClipsDic[name];
        source.Play();

        Destroy(sfxObj, audioClipsDic[name].length);
    }
}

public class GoogleTTSManager : MonoBehaviour
{
    public static GoogleTTSManager Instance;
    private string[] voiceNames = { 
        "ko-KR-Wavenet-A", "ko-KR-Wavenet-B", 
        "ko-KR-Wavenet-C", "ko-KR-Wavenet-D" 
    };

    public void Speak(string text)
    {
        StartCoroutine(RequestTTS(text));
    }

    private IEnumerator RequestTTS(string text)
    {
        string url = "https://texttospeech.googleapis.com" +
                     "/v1/text:synthesize?key=" + apiKey;

        string randomVoice = voiceNames[
            Random.Range(0, voiceNames.Length)];

        string json = "{\"input\":{\"text\":\"" + text + 
            "\"},\"voice\":{\"languageCode\":\"ko-KR\"," +
            "\"name\":\"" + randomVoice + "\"}," +
            "\"audioConfig\":{\"audioEncoding\":\"MP3\"}}";

        using (UnityWebRequest www = 
               new UnityWebRequest(url, "POST"))
        {
            www.uploadHandler = 
                new UploadHandlerRaw(Encoding.UTF8.GetBytes(json));
            www.downloadHandler = new DownloadHandlerBuffer();
            www.SetRequestHeader("Content-Type", 
                                 "application/json");

            yield return www.SendWebRequest();

            // Base64 디코딩 후 재생
            string audioContent = JsonUtility
                .FromJson<TTSResponse>(www.downloadHandler.text)
                .audioContent;
            byte[] audioBytes = 
                System.Convert.FromBase64String(audioContent);
            StartCoroutine(PlayAudioClip(audioBytes));
        }
    }
}

public class GameManager : MonoBehaviour
{
    public static GameManager instance;
    public float Timer = 3f;

    public void TimerInit() 
    {
        Timer = TimerOffset;
        timerTMP.text = Timer.ToString("F2");
        isTimerPaused = false;
    }

    public void TimerSub()
    {
        if (isTimerPaused) return;
        Timer -= Time.deltaTime;
        if (Timer < 0f) {
            Timer = 0f;
            GameOver();
        }
        timerTMP.text = Timer.ToString("F2");
    }

    public void GameClear()
    {
        if (isCleared) return;
        isCleared = true; 
        TimerStop();
        UIManager.Instance.OnGameStateChanged(
            GameState.Clear, DataManager.Instance.deathCount);
    }

    public void GameOver()
    {
        if (isOverlapDie || isCleared) return; 
        isOverlapDie = true;
        UIManager.Instance.OnGameStateChanged(GameState.Replay);
        deathCommentUI.ShowComment();
        SoundManager.Instance.PlaySFXSound(
            $"fail{Random.Range(1,5)}Sfx");
    }
}
